"""
Identité visuelle Djiguignè AI — module de thème partagé.

Un seul endroit pour tout ce qui touche à la marque : couleurs, polices,
animations, logo, en-tête. Chaque page (vitrine, créer_agent, mes_agents)
importe et appelle injecter_theme() en tout premier, avant tout autre
st.markdown/st.write, pour que le CSS s'applique dès le premier rendu.

Pourquoi un fichier dédié plutôt que du CSS copié-collé dans chaque page :
une seule marque à faire évoluer (ex: changer l'accent orange) = un seul
fichier à toucher, pas cinq. Le logo est embarqué en base64 (pas de
dépendance à un fichier image sur le serveur -> fonctionne à l'identique
sur Streamlit Cloud, Railway, ou en local sans étape de build supplémentaire).
"""

import streamlit as st

# Logo Djiguignè AI, fond détouré (transparent), recadré, 256x256.
# Regénéré une fois depuis le PNG original fourni -> voir historique du
# projet si le logo doit être remplacé (meme script de detourage).
LOGO_BASE64 = ""

LOGO_DATA_URI = f"data:image/png;base64,{LOGO_BASE64}"

# --- Tokens de marque ------------------------------------------------------
# Choisis pour trancher avec le "look IA générique" (fond crème + accent
# terracotta + serif) : ici fond quasi-noir chaud (pas un noir bleuté
# tech générique), un seul accent ambre/terracotta qui reprend exactement
# les tons du logo (coucher de soleil sur le baobab), typo grotesque
# distinctive pour les titres plutôt qu'une serif "premium" attendue.
COULEURS = {
    "fond": "#0B0908",
    "surface": "#161210",
    "surface_haute": "#1E1813",
    "bordure": "rgba(255, 255, 255, 0.08)",
    "bordure_forte": "rgba(232, 147, 74, 0.35)",
    "accent_1": "#E8934A",   # ambre clair (highlight du logo)
    "accent_2": "#C1440E",   # terracotta profond (ombre du logo)
    "accent_gradient": "linear-gradient(135deg, #F2A65A 0%, #D9631F 55%, #8A2E0A 100%)",
    "texte": "#F5ECE0",
    "texte_muet": "#A79A8C",
    "succes": "#4ADE80",
    "inactif": "#6B6259",
}

CSS = """
<style>
@import url('https://fonts.googleapis.com/css2?family=Bricolage+Grotesque:opsz,wght@12..96,400..800&family=Inter:wght@400;500;600;700&family=JetBrains+Mono:wght@400;500&display=swap');

:root {
    --dj-fond: #0B0908;
    --dj-surface: #161210;
    --dj-surface-haute: #1E1813;
    --dj-bordure: rgba(255,255,255,0.08);
    --dj-bordure-forte: rgba(232,147,74,0.35);
    --dj-accent-1: #E8934A;
    --dj-accent-2: #C1440E;
    --dj-gradient: linear-gradient(135deg, #F2A65A 0%, #D9631F 55%, #8A2E0A 100%);
    --dj-texte: #F5ECE0;
    --dj-texte-muet: #A79A8C;
    --dj-succes: #4ADE80;
    --dj-inactif: #6B6259;
}

/* --- Fond général & habillage Streamlit ------------------------------- */
.stApp {
    background: radial-gradient(ellipse 120% 60% at 50% -10%, rgba(232,147,74,0.10), transparent 60%), var(--dj-fond) !important;
    color: var(--dj-texte);
    font-family: 'Inter', sans-serif;
}
[data-testid="stHeader"] { background: transparent !important; }
#MainMenu, footer, [data-testid="stDecoration"], [data-testid="stStatusWidget"] { visibility: hidden !important; height: 0 !important; }
[data-testid="stSidebar"] {
    background: #0E0B09 !important;
    border-right: 1px solid var(--dj-bordure);
}
[data-testid="stSidebarNav"] li a { color: var(--dj-texte-muet) !important; font-family: 'Inter', sans-serif; }
[data-testid="stSidebarNav"] li a[aria-current="page"] { color: var(--dj-accent-1) !important; font-weight: 600; }
.block-container { padding-top: 2.2rem !important; max-width: 1080px; }

h1, h2, h3, .dj-display {
    font-family: 'Bricolage Grotesque', sans-serif !important;
    color: var(--dj-texte) !important;
    letter-spacing: -0.01em;
}
p, span, label, .stCaption, div[data-testid="stCaptionContainer"] { color: var(--dj-texte); }
.stCaption, [data-testid="stCaptionContainer"] p { color: var(--dj-texte-muet) !important; }
hr { border-color: var(--dj-bordure) !important; }

/* --- Boutons ----------------------------------------------------------- */
.stButton > button, .stFormSubmitButton > button, .stDownloadButton > button, .stLinkButton > a {
    background: var(--dj-gradient) !important;
    color: #1A0D02 !important;
    font-weight: 700 !important;
    border: none !important;
    border-radius: 10px !important;
    padding: 0.55rem 1.1rem !important;
    box-shadow: 0 2px 14px rgba(217,99,31,0.25);
    transition: transform 0.15s ease, box-shadow 0.15s ease;
}
.stButton > button:hover, .stFormSubmitButton > button:hover, .stLinkButton > a:hover {
    transform: translateY(-2px);
    box-shadow: 0 6px 22px rgba(217,99,31,0.4);
}
.stButton > button:active { transform: translateY(0); }
/* Boutons secondaires (déconnexion, annuler) : plus discrets */
.stButton > button:has(> div > p:contains("Déconnexion")) { background: transparent !important; }

/* --- Champs de saisie ---------------------------------------------------*/
.stTextInput input, .stTextArea textarea, .stNumberInput input {
    background: var(--dj-surface) !important;
    color: var(--dj-texte) !important;
    border: 1px solid var(--dj-bordure) !important;
    border-radius: 8px !important;
}
.stTextInput input:focus, .stTextArea textarea:focus {
    border-color: var(--dj-accent-1) !important;
    box-shadow: 0 0 0 1px var(--dj-accent-1) !important;
}
div[data-baseweb="select"] > div {
    background: var(--dj-surface) !important;
    border-color: var(--dj-bordure) !important;
    color: var(--dj-texte) !important;
    border-radius: 8px !important;
}
.stCheckbox label, .stRadio label { color: var(--dj-texte) !important; }
[data-baseweb="radio"] div:first-child { border-color: var(--dj-accent-1) !important; }

/* --- Cartes / conteneurs bordés (expanders, st.container(border=True)) --*/
div[data-testid="stExpander"], div[data-testid="stVerticalBlockBorderWrapper"] {
    background: var(--dj-surface) !important;
    border: 1px solid var(--dj-bordure) !important;
    border-radius: 14px !important;
    transition: border-color 0.2s ease, transform 0.2s ease;
    animation: dj-fade-up 0.5s ease both;
}
div[data-testid="stExpander"]:hover {
    border-color: var(--dj-bordure-forte) !important;
}
div[data-testid="stExpander"] summary {
    font-family: 'Bricolage Grotesque', sans-serif;
    font-weight: 600;
}

/* --- Tabs ---------------------------------------------------------------*/
button[data-baseweb="tab"] { color: var(--dj-texte-muet) !important; font-family: 'Inter'; }
button[data-baseweb="tab"][aria-selected="true"] {
    color: var(--dj-accent-1) !important;
    border-bottom-color: var(--dj-accent-1) !important;
}

/* --- Badges de statut (utilisés via st.markdown, classes dj-badge-*) ----*/
.dj-badge {
    display: inline-flex; align-items: center; gap: 6px;
    font-family: 'JetBrains Mono', monospace; font-size: 0.72rem;
    padding: 3px 10px; border-radius: 999px; font-weight: 500;
}
.dj-badge-actif { background: rgba(74,222,128,0.12); color: var(--dj-succes); }
.dj-badge-inactif { background: rgba(107,98,89,0.2); color: var(--dj-inactif); }
.dj-badge-dot { width: 6px; height: 6px; border-radius: 50%; background: currentColor; }

/* --- Animations ---------------------------------------------------------*/
@keyframes dj-fade-up {
    from { opacity: 0; transform: translateY(14px); }
    to   { opacity: 1; transform: translateY(0); }
}
@keyframes dj-orbit {
    from { transform: rotate(0deg); }
    to   { transform: rotate(360deg); }
}
@keyframes dj-glow {
    0%, 100% { opacity: 0.55; transform: scale(1); }
    50%      { opacity: 0.9;  transform: scale(1.06); }
}
@keyframes dj-fade-in { from { opacity: 0; } to { opacity: 1; } }

.dj-hero-wrap { animation: dj-fade-in 0.8s ease both; }
.dj-stat-card { animation: dj-fade-up 0.5s ease both; }
</style>
"""


def injecter_theme():
    """A appeler en tout premier sur chaque page (avant st.set_page_config
    n'est pas nécessaire, mais avant tout autre rendu visuel)."""
    st.markdown(CSS, unsafe_allow_html=True)


def afficher_entete(email_utilisateur=None, sur_clic_deconnexion=None, page_active=""):
    """
    Bandeau de marque en haut de chaque page (hors chat, qui garde son
    propre habillage par agent). Logo + nom +, si connecté, l'email et un
    bouton de déconnexion.
    """

    col_logo, col_droite = st.columns([3, 2])
    with col_logo:
        st.markdown(
            f"""
            <div style="display:flex; align-items:center; gap:12px; animation: dj-fade-up 0.5s ease both;">
                <img src="{LOGO_DATA_URI}" style="width:40px; height:40px;" />
                <span style="font-family:'Bricolage Grotesque',sans-serif; font-weight:700;
                             font-size:1.35rem; color:var(--dj-texte); letter-spacing:-0.02em;">
                    Djiguignè <span style="color:var(--dj-accent-1);">AI</span>
                </span>
            </div>
            """,
            unsafe_allow_html=True,
        )
    with col_droite:
        if email_utilisateur:
            c1, c2 = st.columns([3, 1.3])
            with c1:
                st.markdown(
                    f"""<div style="text-align:right; padding-top:10px; font-family:'JetBrains Mono',monospace;
                    font-size:0.78rem; color:var(--dj-texte-muet);">{email_utilisateur}</div>""",
                    unsafe_allow_html=True,
                )
            with c2:
                if sur_clic_deconnexion and st.button("Déconnexion", key="dj_deconnexion_entete", use_container_width=True):
                    sur_clic_deconnexion()
    st.markdown("<div style='height:0.6rem'></div>", unsafe_allow_html=True)
    st.markdown(f"<hr style='margin:0 0 1.6rem 0; opacity:0.5;'>", unsafe_allow_html=True)


def afficher_logo_hero(taille=132):
    """Logo central avec halo pulsant + anneau orbital animé -- signature
    visuelle reprise du logo lui-même (le petit point + arc de cercle du
    fichier source), agrandie et animée pour la page vitrine."""

    st.markdown(
        f"""
        <div class="dj-hero-wrap" style="display:flex; justify-content:center; margin: 1.5rem 0 0.5rem 0;">
          <div style="position:relative; width:{taille+70}px; height:{taille+70}px; display:flex; align-items:center; justify-content:center;">
            <div style="position:absolute; width:{taille+60}px; height:{taille+60}px; border-radius:50%;
                        background: radial-gradient(circle, rgba(232,147,74,0.35) 0%, transparent 70%);
                        animation: dj-glow 3.2s ease-in-out infinite;"></div>
            <div style="position:absolute; width:{taille+40}px; height:{taille+40}px; border-radius:50%;
                        border: 1px dashed rgba(232,147,74,0.3);
                        animation: dj-orbit 18s linear infinite;">
              <div style="position:absolute; top:-4px; left:calc(50% - 4px); width:8px; height:8px;
                          border-radius:50%; background: var(--dj-accent-1);
                          box-shadow: 0 0 10px 2px rgba(232,147,74,0.7);"></div>
            </div>
            <img src="{LOGO_DATA_URI}" style="width:{taille}px; height:{taille}px; position:relative; z-index:2;
                 filter: drop-shadow(0 8px 24px rgba(0,0,0,0.5));" />
          </div>
        </div>
        """,
        unsafe_allow_html=True,
    )
